def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    import math

    def distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def travel_time(p1, p2, speed):
        return distance(p1, p2) / speed

    def evaluate_customer(idx):
        customer_pos = unvisited_customers[idx]
        arrival_time = current_time + travel_time(cur_truck_pos, customer_pos, truck_speed)
        window_start, window_end = time_windows[idx]

        wait_time = max(0, window_start - arrival_time)
        penalty = math.inf if arrival_time > window_end else 0
        total_cost = wait_time + penalty

        other_trucks_cost = 0
        for pos in all_truck_pos:
            if pos is not None and not np.array_equal(pos, cur_truck_pos):
                other_trucks_cost += travel_time(pos, depot_pos, truck_speed)

        return total_cost + other_trucks_cost

    best_node = None
    best_score = float('inf')

    for idx in range(len(unvisited_customers)):
        score = evaluate_customer(idx)
        if score < best_score:
            best_score = score
            best_node = idx

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def compute_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    def compute_time_to_customer(from_pos, to_pos, speed):
        return compute_distance(from_pos, to_pos) / speed

    best_node = None
    best_score = float('inf')

    for idx, customer_pos in enumerate(unvisited_customers):
        travel_time = compute_time_to_customer(cur_truck_pos, customer_pos, truck_speed)
        arrival_time = current_time + travel_time
        time_window_start, time_window_end = time_windows[idx]

        if arrival_time <= time_window_start:
            wait_time = time_window_start - arrival_time
            penalty = 0
        elif time_window_start < arrival_time <= time_window_end:
            wait_time = 0
            penalty = 0
        else:
            wait_time = 0
            penalty = arrival_time - time_window_end

        total_time = travel_time + wait_time + penalty
        proximity_score = total_time
        avg_distance_to_other_trucks = np.mean([compute_distance(customer_pos, truck_pos) for truck_pos in all_truck_pos])
        score = proximity_score + avg_distance_to_other_trucks

        if score < best_score:
            best_score = score
            best_node = idx

    return best_node
